  `HoTen` varchar(255) COLLATE utf16_unicode_ci DEFAULT NULL,
  `GioiTinh` varchar(10) COLLATE utf16_unicode_ci DEFAULT NULL,
  `SoCMT` varchar(20) COLLATE utf16_unicode_ci DEFAULT NULL,
